function.body:
v_Display VARCHAR2(200):='';
  v_sql VARCHAR2(2000):='';
BEGIN

  IF ( p_tablename = 'C_Invoice' ) THEN
    v_sql:='SELECT em_spdn_documentno FROM ' || p_tablename ||' WHERE '|| p_tablename || '_id = ''' || p_record_id || '''';
    EXECUTE IMMEDIATE v_sql INTO v_Display;
  END IF;

  IF ( p_tablename = 'FIN_Finacc_Transaction' ) THEN
    v_sql:='SELECT em_sfadt_documentno FROM ' || p_tablename ||' WHERE '|| p_tablename || '_id = ''' || p_record_id || '''';
    EXECUTE IMMEDIATE v_sql INTO v_Display;
  END IF;

 RETURN v_Display;
EXCEPTION
WHEN OTHERS THEN
  RETURN '';
END SACGLD_FACTACCT_TRANSNO
